function ilct_info_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('ilct_info');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'ilct_info_title' => br2nl(Request::val('ilct_info_title', '')),
		'ilct_info_description' => br2nl(Request::val('ilct_info_description', '')),
		'ilct_info_link' => br2nl(Request::val('ilct_info_link', '')),
		'ilct_info_user' => br2nl(Request::val('ilct_info_user', '')),
		'ilct_info_pass' => br2nl(Request::val('ilct_info_pass', '')),
		'ilct_info_token' => br2nl(Request::val('ilct_info_token', '')),
		'ilct_info_pass_code' => br2nl(Request::val('ilct_info_pass_code', '')),
		'ilct_info_related_table' => Request::val('ilct_info_related_table', ''),
		'ilct_info_created' => parseCode('<%%creationTimestamp%%>', true, true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('ilct_info', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		ilct_info_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function ilct_info_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function ilct_info_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('ilct_info', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: ilct_info_before_delete
	if(function_exists('ilct_info_before_delete')) {
		$args = [];
		if(!ilct_info_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `ilct_info` WHERE `ilct_info_id`='{$selected_id}'", $eo);

	// hook: ilct_info_after_delete
	if(function_exists('ilct_info_after_delete')) {
		$args = [];
		ilct_info_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='ilct_info' AND `pkValue`='{$selected_id}'", $eo);
}

function ilct_info_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('ilct_info', $selected_id, 'edit')) return false;

	$data = [
		'ilct_info_title' => br2nl(Request::val('ilct_info_title', '')),
		'ilct_info_description' => br2nl(Request::val('ilct_info_description', '')),
		'ilct_info_link' => br2nl(Request::val('ilct_info_link', '')),
		'ilct_info_user' => br2nl(Request::val('ilct_info_user', '')),
		'ilct_info_pass' => br2nl(Request::val('ilct_info_pass', '')),
		'ilct_info_token' => br2nl(Request::val('ilct_info_token', '')),
		'ilct_info_pass_code' => br2nl(Request::val('ilct_info_pass_code', '')),
		'ilct_info_related_table' => Request::val('ilct_info_related_table', ''),
		'ilct_info_updated' => parseCode('<%%editingTimestamp%%>', false, true),
	];

	if($data['ilct_info_title'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'ILCT INFO Title': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('ilct_info', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: ilct_info_before_update
	if(function_exists('ilct_info_before_update')) {
		$args = ['old_data' => $old_data];
		if(!ilct_info_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'ilct_info',
		backtick_keys_once($set),
		['`ilct_info_id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="ilct_info_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('ilct_info', $data['selectedID'], calculated_fields()['ilct_info']);

	// hook: ilct_info_after_update
	if(function_exists('ilct_info_after_update')) {
		if($row = getRecord('ilct_info', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['ilct_info_id'];
		$args = ['old_data' => $old_data];
		if(!ilct_info_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('ilct_info', $selected_id);
}

