		$templateCode = str_replace('<%%URLVALUE(ilct_info_pass)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(ilct_info_token)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(ilct_info_token)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(ilct_info_pass_code)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(ilct_info_pass_code)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(ilct_info_related_table)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(ilct_info_related_table)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(ilct_info_created)%%>', '<%%creationTimestamp%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(ilct_info_created)%%>', urlencode('<%%creationTimestamp%%>'), $templateCode);
		$templateCode = str_replace('<%%VALUE(ilct_info_updated)%%>', '<%%editingTimestamp%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(ilct_info_updated)%%>', urlencode('<%%editingTimestamp%%>'), $templateCode);
	}

	// process translations
	$templateCode = parseTemplate($templateCode);

	// clear scrap
	$templateCode = str_replace('<%%', '<!-- ', $templateCode);
	$templateCode = str_replace('%%>', ' -->', $templateCode);

	// hide links to inaccessible tables
	if(Request::val('dvprint_x') == '') {
		$templateCode .= "\n\n<script>\$j(function() {\n";
		$arrTables = getTableList();
		foreach($arrTables as $name => $caption) {
			$templateCode .= "\t\$j('#{$name}_link').removeClass('hidden');\n";
			$templateCode .= "\t\$j('#xs_{$name}_link').removeClass('hidden');\n";
		}

		$templateCode .= $jsReadOnly;
		$templateCode .= $jsEditable;

		if(!$hasSelectedId) {
		}

		$templateCode.="\n});</script>\n";
	}

	// ajaxed auto-fill fields
	$templateCode .= '<script>';
	$templateCode .= '$j(function() {';


	$templateCode.="});";
	$templateCode.="</script>";
	$templateCode .= $lookups;

	// handle enforced parent values for read-only lookup fields
	$filterField = Request::val('FilterField');
	$filterOperator = Request::val('FilterOperator');
	$filterValue = Request::val('FilterValue');

	// don't include blank images in lightbox gallery
	$templateCode = preg_replace('/blank.gif" data-lightbox=".*?"/', 'blank.gif"', $templateCode);

	// don't display empty email links
	$templateCode=preg_replace('/<a .*?href="mailto:".*?<\/a>/', '', $templateCode);

	/* default field values */
	$rdata = $jdata = get_defaults('ilct_info');
	if($hasSelectedId) {
		$jdata = get_joined_record('ilct_info', $selectedId);
		if($jdata === false) $jdata = get_defaults('ilct_info');
		$rdata = $row;
	}
	$templateCode .= loadView('ilct_info-ajax-cache', ['rdata' => $rdata, 'jdata' => $jdata]);

	// hook: ilct_info_dv
	if(function_exists('ilct_info_dv')) {
		$args = [];
		ilct_info_dv(($hasSelectedId ? $selectedId : FALSE), getMemberInfo(), $templateCode, $args);
	}

	return $templateCode;
}